# Problem: Build a simplified Django REST Framework serializer system.
#
# Approach: Implement a Field hierarchy with type/constraint validation,
# a ValidationError exception, and a Serializer base class that uses
# class-attribute introspection to discover fields and validate input data.
#
# Time complexity: O(n) where n is the number of fields
# Space complexity: O(n) for storing errors and validated data
#
# Key steps:
# 1. Define ValidationError with a .message attribute
# 2. Implement Field base class, CharField, IntegerField, EmailField with validation
# 3. Implement Serializer with _get_fields(), is_valid(), and serialize()


class ValidationError(Exception):
    def __init__(self, message: str):
        self.message = message
        super().__init__(message)


class Field:
    def __init__(self, required=True, default=None):
        self.required = required
        self.default = default

    def validate(self, value):
        return value


class CharField(Field):
    def __init__(self, required=True, default=None, max_length=None, min_length=None):
        super().__init__(required, default)
        self.max_length = max_length
        self.min_length = min_length

    def validate(self, value):
        if not isinstance(value, str):
            raise ValidationError("Expected a string.")
        if self.max_length is not None and len(value) > self.max_length:
            raise ValidationError(f"String length must be <= {self.max_length}.")
        if self.min_length is not None and len(value) < self.min_length:
            raise ValidationError(f"String length must be >= {self.min_length}.")
        return value


class IntegerField(Field):
    def __init__(self, required=True, default=None, min_value=None, max_value=None):
        super().__init__(required, default)
        self.min_value = min_value
        self.max_value = max_value

    def validate(self, value):
        # Reject bools first since bool is a subclass of int in Python
        if isinstance(value, bool) or not isinstance(value, int):
            raise ValidationError("Expected an integer.")
        if self.min_value is not None and value < self.min_value:
            raise ValidationError(f"Value must be >= {self.min_value}.")
        if self.max_value is not None and value > self.max_value:
            raise ValidationError(f"Value must be <= {self.max_value}.")
        return value


class EmailField(CharField):
    def validate(self, value):
        value = super().validate(value)  # Run CharField's str/length checks first
        parts = value.split("@")
        # Must have exactly one '@' with non-empty text on both sides
        if len(parts) != 2 or not parts[0] or not parts[1]:
            raise ValidationError("Invalid email format")
        return value


class Serializer:
    def __init__(self, data=None):
        self.data = data or {}
        self.errors = {}
        self.validated_data = {}

    def _get_fields(self):
        # Walk the MRO to collect Field instances from this class and parents
        fields = {}
        for cls in reversed(type(self).__mro__):
            for k, v in cls.__dict__.items():
                if isinstance(v, Field):
                    fields[k] = v
        return fields

    def is_valid(self):
        self.errors = {}
        self.validated_data = {}

        for name, field in self._get_fields().items():
            if name not in self.data:
                if field.required and field.default is None:
                    self.errors[name] = "This field is required."
                else:
                    # Use default for missing optional fields
                    self.validated_data[name] = field.default
            else:
                try:
                    self.validated_data[name] = field.validate(self.data[name])
                except ValidationError as e:
                    self.errors[name] = e.message

        return len(self.errors) == 0

    def serialize(self, obj: dict) -> dict:
        # Return only keys that correspond to declared fields
        fields = self._get_fields()
        return {k: v for k, v in obj.items() if k in fields}
